import anthropic
from concurrent.futures import ThreadPoolExecutor, as_completed

client = anthropic.Anthropic()


def plan_subtasks(task: str) -> list[str]:
    """Ask the model to decompose the task into named subtasks."""
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=200,
        messages=[{
            "role": "user",
            "content": (
                f"Break this task into 3-5 independent subtasks. "
                f"List only the subtask names, one per line:\n{task}"
            ),
        }],
    )
    return [line.strip(" -") for line in resp.content[0].text.strip().splitlines() if line.strip()]


def execute_subtask(task: str, subtask: str) -> tuple[str, str]:
    """Execute a single subtask and return (subtask_name, result)."""
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=300,
        messages=[{
            "role": "user",
            "content": f"For the overall task: {task}\n\nComplete this subtask: {subtask}",
        }],
    )
    return subtask, resp.content[0].text.strip()


def synthesise(task: str, results: dict[str, str]) -> str:
    joined = "\n\n".join(f"## {k}\n{v}" for k, v in results.items())
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=500,
        messages=[{
            "role": "user",
            "content": f"Task: {task}\n\nSubtask results:\n{joined}\n\nSynthesize into a final answer.",
        }],
    )
    return resp.content[0].text.strip()


task = "Analyse the pros and cons of microservices vs monolith architectures for a startup."

subtasks = plan_subtasks(task)
print(f"Planned subtasks: {subtasks}")

results: dict[str, str] = {}
with ThreadPoolExecutor(max_workers=len(subtasks)) as ex:
    futs = {ex.submit(execute_subtask, task, st): st for st in subtasks}
    for fut in as_completed(futs):
        name, result = fut.result()
        results[name] = result
        print(f"  Completed: {name}")

final = synthesise(task, results)
print("\nFinal answer:", final[:300])

import anthropic
from concurrent.futures import ThreadPoolExecutor
from dataclasses import dataclass

client = anthropic.Anthropic()


@dataclass
class ModerationResult:
    dimension: str
    flagged: bool
    confidence: float
    reason: str


DIMENSION_PROMPTS = {
    "hate_speech": (
        "Evaluate this text for hate speech targeting protected characteristics. "
        "Respond with: FLAGGED or SAFE, confidence 0.0-1.0, one-sentence reason.\n\nText: {text}"
    ),
    "misinformation": (
        "Evaluate this text for factual misinformation about health, science, or elections. "
        "Respond with: FLAGGED or SAFE, confidence 0.0-1.0, reason.\n\nText: {text}"
    ),
    "spam": (
        "Evaluate whether this text is spam or unsolicited promotion. "
        "Respond with: FLAGGED or SAFE, confidence 0.0-1.0, reason.\n\nText: {text}"
    ),
}


def check_dimension(text: str, dimension: str, prompt_template: str) -> ModerationResult:
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=80,
        temperature=0.0,
        messages=[{"role": "user", "content": prompt_template.format(text=text)}],
    )
    raw = resp.content[0].text.strip()
    parts = raw.split(",", 2)
    flagged = parts[0].strip() == "FLAGGED"
    try:
        confidence = float(parts[1].strip())
    except (IndexError, ValueError):
        confidence = 0.5
    reason = parts[2].strip() if len(parts) > 2 else "No reason provided"
    return ModerationResult(dimension, flagged, confidence, reason)


def moderate_post(text: str) -> list[ModerationResult]:
    with ThreadPoolExecutor(max_workers=len(DIMENSION_PROMPTS)) as ex:
        futs = [
            ex.submit(check_dimension, text, dim, tmpl)
            for dim, tmpl in DIMENSION_PROMPTS.items()
        ]
        return [f.result() for f in futs]


posts = [
    "Buy cheap followers NOW! 10,000 for $5 - guaranteed!",
    "Vaccines contain microchips that track your location.",
    "Just finished reading a great book, highly recommend it!",
]

for post in posts:
    results = moderate_post(post)
    flagged = [r for r in results if r.flagged]
    status = "REMOVE" if any(r.confidence > 0.8 for r in flagged) else ("REVIEW" if flagged else "OK")
    print(f"[{status}] {post[:50]}")
    for r in flagged:
        print(f"  {r.dimension}: {r.reason} (conf={r.confidence:.2f})")
